 Python Approach

import requests
import json
import time

def scrape_shopify_products(store_url):
 products = []
 page = 1
 limit = 250

 session = requests.Session()
 session.headers.update({
 'User-Agent': 'Mozilla/5.0 (compatible; ProductResearch/1.0)'
 })

 while True:
 url = f"{store_url}/products.json?page={page}&limit={limit}"

 try:
 response = session.get(url, timeout=30)

 if response.status_code == 429:
 print("Rate limited. Waiting 30 seconds...")
 time.sleep(30)
 continue

 response.raise_for_status()
 data = response.json()

 page_products = data.get('products', [])
 if not page_products:
 break

 for product in page_products:
 products.append({
 'id': product['id'],
 'title': product['title'],
 'vendor': product['vendor'],
 'product_type': product['product_type'],
 'handle': product['handle'],
 'tags': product.get('tags', ''),
 'variants': [{
 'id': v['id'],
 'title': v['title'],
 'price': v['price'],
 'compare_at_price': v.get('compare_at_price'),
 'sku': v.get('sku'),
 'available': v.get('available', False),
 } for v in product.get('variants', [])],
 'images': [img['src'] for img in product.get('images', [])]
 })

 print(f"Page {page}: {len(page_products)} products")
 page += 1
 time.sleep(1)

 except requests.exceptions.RequestException as e:
 print(f"Error on page {page}: {e}")
 break

 print(f"Total: {len(products)} products")
 return products

# Usage
products = scrape_shopify_products("https://example-store.myshopify.com")
with open("products.json", "w") as f:
 json.dump(products, f, indent=2)

